import sys

class Solution:
    def uniquePathsWithObstacles(self, grid: list[list[int]]) -> int:
        m, n = len(grid), len(grid[0])
        dp = [[0] * n for _ in range(m)]
        dp[0][0] = 1 - grid[0][0]
        for i in range(1, m):
            dp[i][0] = dp[i - 1][0] * (1 - grid[i][0])
        for j in range(1, n):
            dp[0][j] = dp[0][j - 1] * (1 - grid[0][j])
        for i in range(1, m):
            for j in range(1, n):
                if grid[i][j] == 0:
                    dp[i][j] = dp[i - 1][j] + dp[i][j - 1]
        return dp[-1][-1]

